def arrange_alt(str1, str2):
    max_len = max(len(str1), len(str2))
    result = []
    for i in range(max_len):
        if i < len(str1):
            result.append(str1[i])
        if i < len(str2):
            result.append(str2[i])
    return "".join(result)
